 1	import { Switch, Text, TextVariants, Tooltip } from '@patternfly/react-core';
 2	import { InfoAltIcon } from '@patternfly/react-icons';
 3	import * as React from 'react';
 4	import { useTranslation } from 'react-i18next';
 5	import { FlowScope } from '../../model/flow-query';
 6	
 7	import { ScopeConfigDef } from '../../model/scope';
 8	import ScopeDropdown from './scope-dropdown';
 9	import TruncateDropdown, { TruncateLength } from './truncate-dropdown';
10	
11	export type Size = 's' | 'm' | 'l';
12	
13	export interface OverviewDisplayOptionsProps {
14	  metricScope: FlowScope;
15	  setMetricScope: (s: FlowScope) => void;
16	  truncateLength: TruncateLength;
17	  setTruncateLength: (v: TruncateLength) => void;
18	  focus: boolean;
19	  setFocus: (v: boolean) => void;
20	  scopes: ScopeConfigDef[];
21	}
22	
23	export const OverviewDisplayOptions: React.FC<OverviewDisplayOptionsProps> = ({
24	  metricScope,
25	  setMetricScope,
26	  truncateLength,
27	  setTruncateLength,
28	  focus,
29	  setFocus,
30	  scopes
31	}) => {
32	  const { t } = useTranslation('plugin__netobserv-plugin');
33	
34	  return (
35	    <>
36	      <div className="pf-v6-c-menu__group">
37	        <Tooltip content={t('The level of details represented.')}>
38	          <div className="pf-v6-c-menu__group-title">
39	            <Text component={TextVariants.p}>
40	              {t('Scope')} <InfoAltIcon />
41	            </Text>
42	          </div>
43	        </Tooltip>
44	        <div className="display-dropdown-padding">
45	          <ScopeDropdown
46	            data-test="scope"
47	            id="scope"
48	            selected={metricScope}
49	            setScopeType={setMetricScope}
50	            scopes={scopes}
51	          />
52	        </div>
53	      </div>
54	      <div className="pf-v6-c-menu__group">
55	        <Tooltip content={t('Long labels can reduce visibility.')}>
56	          <div className="pf-v6-c-menu__group-title">
57	            <Text component={TextVariants.p}>
58	              {t('Truncate labels')} <InfoAltIcon />
59	            </Text>
60	          </div>
61	        </Tooltip>
62	        <div className="display-dropdown-padding">
63	          <TruncateDropdown id="truncate" selected={truncateLength} setTruncateLength={setTruncateLength} />
64	        </div>
65	      </div>
66	      <div className="pf-v6-c-menu__group">
67	        <div className="display-dropdown-switch-padding">
68	          <Switch
69	            id="focus-switch"
70	            label={t('Single graph focus')}
71	            isChecked={focus}
72	            onChange={(event, value) => setFocus(value)}
73	            isReversed
74	          />
75	        </div>
76	      </div>
77	    </>
78	  );
79	};
80	
81	export default OverviewDisplayOptions;

